'use strict';const ERROR_COLOR="#F00";const ERROR_BG_COLOR="#FAA";const highlightFields=(formId,fields)=>{fields.forEach((field)=>{$(`#${formId} input[name=${field}]`).css("background-color",ERROR_BG_COLOR);$(`#${formId} label[for=${field}]`).css("color",ERROR_COLOR);});};const highlightReset=(formId)=>{$(`#${formId} input`).css("background-color","");$(`#${formId} label`).css("color","");};const displayErrors=(formId,errors)=>{errors.forEach((error)=>{const location=error.loc[1];const msg=error.msg;highlightFields(formId,[location]);const $parentDiv=$(`#${formId}`).find(`#${location}`).closest(".control-holder");$parentDiv.prepend(`<div class='error-message'>${msg}</div>`);});};const displayError=(formId,inputId,errorMsg)=>{highlightFields(formId,[inputId]);const $parentDiv=$(`#${formId}`).find(`#${inputId}`).closest(".control-holder");$parentDiv.prepend(`<div class='error-message'>${errorMsg}</div>`);};const clearErrors=(formId)=>{highlightReset(formId);$(`#${formId} .error-message`).remove();};const keypressNumberOnly=(event)=>{const regex=/^[0-9]+$/;const key=String.fromCharCode(event.charCode||event.which);if(!regex.test(key)){event.preventDefault();return false;}};const submitOnce=(button)=>{button.disabled=true;button.textContent="Submitting...";button.form.submit();};const preventDoubleSubmission=()=>{$('form').submit(function(){$(this).find(':submit').attr('disabled','disabled');});};$(()=>{preventDoubleSubmission();});'use strict';const postJson=(url,json)=>{return $.ajax({type:"POST",url:url,contentType:"application/json",data:JSON.stringify(json)});};const ajaxFailure=(data,status,error)=>{console.error('Ajax Error:',error,data.responseText);alert(`Error: ${error}\n${data.responseText}`);};